text-to-text.frontend_code:
// Step 1: Read user prompt and active LLM model from React state
const promptText = input.trim();
const selectedModel = model || 'gemini-2.5-flash';

// Step 2: Build FormData payload with required parameters for text mode
const formData = new FormData();
formData.append('mode', 'text');             // Set mode to text
formData.append('query', promptText);        // Send user query string
formData.append('model_name', selectedModel); // Selected LLM model ID
formData.append('output_format', 'text');    // Request text output format

// Step 3: Send POST request to backend FastAPI chat endpoint
const response = await fetch('http://127.0.0.1:8000/api/chat', {
  method: 'POST',
  body: formData,
});

// Step 4: Parse returned JSON data containing LLM output
const data = await response.json();

// Step 5: Append AI response text to Chat message list state
setMessages((prevMessages) => [
  ...prevMessages,
  { role: 'assistant', content: data.response }
]);

