text-to-image.frontend_code:
// Step 1: Read user prompt and set FLUX image generation model
const promptText = input.trim();
const imageModel = 'black-forest-labs/FLUX.1-schnell';

// Step 2: Build FormData payload requesting image output format
const formData = new FormData();
formData.append('mode', 'text');             // Mode is text prompt input
formData.append('query', promptText);        // Image description query
formData.append('model_name', imageModel);   // FLUX.1-schnell model ID
formData.append('output_format', 'image');   // Output format requested: image

// Step 3: Send POST request to backend API endpoint
const response = await fetch('http://127.0.0.1:8000/api/chat', {
  method: 'POST',
  body: formData,
});

// Step 4: Parse response JSON containing image file URL
const data = await response.json();
const fullImageUrl = `http://127.0.0.1:8000${data.image_file}`;

// Step 5: Render assistant message containing generated image in UI
setMessages((prevMessages) => [
  ...prevMessages,
  { role: 'assistant', content: data.response, imageUrl: fullImageUrl }
]);

