text-to-speech.frontend_code:
// Step 1: Set output format to 'audio' in FormData
const formData = new FormData();
formData.append('mode', 'text');
formData.append('query', textInput);
formData.append('output_format', 'audio');

// Step 2: Post request to backend API
const response = await fetch('http://127.0.0.1:8000/api/chat', { method: 'POST', body: formData });
const data = await response.json();

// Step 3: Render response message with audio player widget
setMessages((prev) => [
  ...prev,
  { role: 'assistant', content: data.response, audioUrl: `http://127.0.0.1:8000${data.audio_file}` }
]);

